foreach my $arg (@ARGV) {
    if ($arg eq '--compress') {
        $do_compress = 1;
    } elsif ($arg eq '--checksum') {
        $do_checksum = 1;
    } elsif ($arg eq '--list') {
        $do_list = 1;
